<template><div class="page"><div class="toolbar"><h1>司机审核</h1><el-select v-model="status" clearable @change="load"><el-option label="待审核" value="PENDING"/><el-option label="已通过" value="APPROVED"/><el-option label="已拒绝" value="REJECTED"/><el-option label="已停用" value="DISABLED"/></el-select><el-button @click="load">刷新</el-button></div><el-table :data="rows" border><el-table-column prop="id" label="ID" width="80"/><el-table-column prop="realName" label="姓名"/><el-table-column prop="phone" label="电话"/><el-table-column prop="vehiclePlate" label="车牌"/><el-table-column prop="vehicleTypeName" label="车型"/><el-table-column prop="auditStatus" label="审核"/><el-table-column label="操作" width="260"><template #default="{row}"><el-button type="success" @click="audit(row,'APPROVED')">通过</el-button><el-button type="warning" @click="audit(row,'REJECTED')">拒绝</el-button><el-button type="danger" @click="audit(row,'DISABLED')">停用</el-button></template></el-table-column></el-table></div></template>
<script setup>import {onMounted,ref} from 'vue';import {ElMessage} from 'element-plus';import http from '../api/http';const rows=ref([]);const status=ref('');async function load(){rows.value=await http.get('/admin/drivers',{params:{auditStatus:status.value}})}async function audit(r,s){await http.put(`/admin/driver/${r.id}/audit`,{status:s,reason:'后台操作'});ElMessage.success('审核状态已更新');load()}onMounted(load)</script>
